use aiken/math/rational
use cardano/transaction.{OutputReference, Transaction}

pub type RatioDatum {
  num: Int,
  den: Int,
}

validator ratio_above_half {
  spend(
    datum: Option<RatioDatum>,
    _redeemer: Data,
    _ref: OutputReference,
    _self: Transaction,
  ) -> Bool {
    when datum is {
      None -> False
      Some(d) ->
        when rational.new(d.num, d.den) is {
          None -> False
          Some(r) ->
            rational.compare_with(r, fn(a, b) { a * 2 > b }, rational.new(1, 2) |> option.or_else(rational.zero))
        }
    }
  }

  else(_) {
    False
  }
}
